    "html": "<div class=\"lt pos-bc in-up\">\n  <div class=\"panel quote-panel\" style=\"--bg:#FFFFFF;--fg:#2D2A3A;--accent:#5B4B8A;--bd:rgba(91,75,138,.2);\">\n    <span class=\"kicker\">{{label}}</span>\n    <p class=\"quote-text\">\"{{quote}}\"</p>\n    <p class=\"quote-ref\">{{reference}}</p>\n  </div>\n</div>",
