    "html": "<div class=\"lt pos-br in-up\">\n  <div class=\"panel announce-panel\" style=\"--bg:#FFFFFF;--fg:#2A3948;--accent:#365F8C;--bd:rgba(54,95,140,.22);--tagFg:#fff;\">\n    <span class=\"tag-box\">{{label}}</span>\n    <div class=\"col\">\n      <p class=\"headline\">{{headline}}</p>\n      <p class=\"subline\">{{details}}</p>\n    </div>\n  </div>\n</div>",
