    "html": "<div class=\"lt pos-bc in-up\">\n  <div class=\"panel keyword-panel\" style=\"--bg:rgba(15,23,42,.82);--fg:#F0FDF4;--accent:#22C55E;--bd:rgba(34,197,94,.28);--tagFg:#fff;\">\n    <span class=\"tag-box\">{{label}}</span>\n    <span class=\"keyword-main\">{{keyword}}</span>\n    <span class=\"keyword-sub\">{{supportingText}}</span>\n  </div>\n</div>",
