    "html": "<div class=\"lt pos-bc in-up\">\n  <div class=\"panel announce-panel\" style=\"--bg:rgba(10,18,36,.86);--fg:#ECFEFF;--accent:#06B6D4;--bd:rgba(6,182,212,.3);--tagFg:#fff;\">\n    <span class=\"tag-box\">{{label}}</span>\n    <div class=\"col\">\n      <p class=\"headline\">{{headline}}</p>\n      <p class=\"subline\">{{details}}</p>\n    </div>\n  </div>\n</div>",
