    "html": "<div class=\"lt pos-br in-up\">\n  <div class=\"panel date-shell\" style=\"--bg:rgba(15,23,42,.9);--fg:#F8FAFC;--accent:#2563EB;--bd:rgba(37,99,235,.32);\">\n    <div class=\"date-box\">\n      <span class=\"mth\">{{month}}</span>\n      <span class=\"dy\">{{day}}</span>\n    </div>\n    <div class=\"col\">\n      <p class=\"headline\">{{headline}}</p>\n      <p class=\"subline\">{{details}}</p>\n    </div>\n  </div>\n</div>",
