    "html": "<div class=\"lt pos-br in-up\">\n  <div class=\"panel info-panel\" style=\"--bg:rgba(15,23,42,.9);--fg:#F0FDF4;--accent:#22C55E;--bd:rgba(34,197,94,.3);\">\n    <span class=\"kicker\">{{heading}}</span>\n    <p class=\"headline\">{{line1}}</p>\n    <p class=\"subline\">{{line2}}</p>\n  </div>\n</div>",
