    "html": "<div class=\"lt pos-bl in-up\">\n  <div class=\"panel announce-panel\" style=\"--bg:rgba(22,20,45,.86);--fg:#EEF2FF;--accent:#6366F1;--bd:rgba(99,102,241,.3);--tagFg:#fff;\">\n    <span class=\"tag-box\">{{label}}</span>\n    <div class=\"col\">\n      <p class=\"headline\">{{headline}}</p>\n      <p class=\"subline\">{{details}}</p>\n    </div>\n  </div>\n</div>",
