    "html": "<div class=\"ylt y-pos-br\" data-state=\"{{state}}\" data-mode=\"{{animMode}}\" style=\"--bg1:#2b150b;--bg2:#3a1d10;--fg:#fff8f2;--accent:#fb923c;--muted:rgba(255,232,214,.82);--border:rgba(251,146,60,.35);--glow:rgba(251,146,60,.23);\">\n  <div class=\"y-shell y-give\">\n    <span class=\"y-kicker y-enter-3\">{{heading}}</span>\n    <p class=\"y-line1 y-enter-1\">{{line1}}</p>\n    <p class=\"y-line2 y-enter-2\">{{line2}}</p>\n  </div>\n</div>",
    "usesTailwind": false,
