    "html": "<div class=\"ylt y-pos-br\" data-state=\"{{state}}\" data-mode=\"{{animMode}}\" style=\"--bg1:#1a1338;--bg2:#25194c;--fg:#f8f5ff;--accent:#a78bfa;--muted:rgba(236,229,255,.82);--border:rgba(167,139,250,.34);--glow:rgba(167,139,250,.24);\">\n  <div class=\"y-shell y-give\">\n    <span class=\"y-kicker y-enter-3\">{{heading}}</span>\n    <p class=\"y-line1 y-enter-1\">{{line1}}</p>\n    <p class=\"y-line2 y-enter-2\">{{line2}}</p>\n  </div>\n</div>",
