    "html": "<div class=\"c-lt c-pos-bc\" data-state=\"{{state}}\" data-mode=\"{{animMode}}\" style=\"--bg:linear-gradient(135deg,#0b122a,#1d3f8a);--fg:#f8fbff;--sub:#dbeafe;--accent:#38bdf8;--bd:rgba(56,189,248,.34);--glow:rgba(56,189,248,.2);\">\n  <div class=\"c-shell c-sermon c-row\">\n    <div class=\"c-bar c-e3\"></div>\n    <div class=\"c-sermon-copy\">\n      <span class=\"c-kicker c-e3\">{{label}}</span>\n      <p class=\"c-title c-e1\">{{title}}</p>\n      <p class=\"c-sub c-e2\">{{subtitle}}</p>\n      <p class=\"c-meta c-e3\">{{meta}}</p>\n    </div>\n  </div>\n</div>",
