    "css": "\n* { box-sizing: border-box; margin: 0; padding: 0; }\nhtml, body { width: 100%; height: 100%; overflow: hidden; background: transparent; }\nbody { font-family: \"Montserrat\", sans-serif; }\n\n@keyframes s5FadeUp {\n  from { opacity: 0; transform: translateY(16px); }\n  to { opacity: 1; transform: translateY(0); }\n}\n@keyframes s5Ticker {\n  0% { transform: translateX(0%); }\n  100% { transform: translateX(-50%); }\n}\n@keyframes s5Pulse {\n  0%, 100% { opacity: 1; }\n  50% { opacity: .45; }\n}\n@keyframes s5Cycle {\n  0% { opacity: 0; transform: translateY(8px); }\n  8% { opacity: 1; transform: translateY(0); }\n  30% { opacity: 1; transform: translateY(0); }\n  35% { opacity: 0; transform: translateY(-8px); }\n  100% { opacity: 0; transform: translateY(-8px); }\n}\n\n.s5 {\n  position: fixed;\n  z-index: 70;\n  pointer-events: none;\n  color: #0f172a;\n}\n\n.s5-pos-bl { left: 32px; bottom: 30px; }\n.s5-pos-br { right: 32px; bottom: 30px; }\n.s5-pos-bc { left: 50%; bottom: 30px; transform: translateX(-50%); }\n.s5-pos-full { left: 0; right: 0; bottom: 0; }\n\n.s5-enter { animation: s5FadeUp .62s cubic-bezier(0.16, 1, 0.3, 1) both; }\n\n.s5-panel {\n  border: 1px solid rgba(15, 23, 42, 0.14);\n  background: rgba(255, 255, 255, 0.96);\n  border-radius: 14px;\n  box-shadow: 0 12px 38px rgba(0,0,0,.24);\n}\n\n.s5-label {\n  border-radius: 999px;\n  background: #1d4ed8;\n  color: #fff;\n  text-transform: uppercase;\n  letter-spacing: .11em;\n  font-size: 11px;\n  font-weight: 800;\n  padding: 8px 12px;\n  display: inline-flex;\n  align-items: center;\n  gap: 8px;\n}\n\n.s5-chip {\n  border: 1px solid rgba(15, 23, 42, 0.12);\n  background: #fff;\n  border-radius: 999px;\n  display: inline-flex;\n  align-items: center;\n  gap: 8px;\n  padding: 8px 12px;\n  font-size: clamp(15px, 1.05vw, 20px);\n  font-weight: 700;\n  color: #111827;\n}\n\n.s5-chip i {\n  width: 1.2em;\n  text-align: center;\n}\n\n.s5-facebook i { color: #1877F2; }\n.s5-twitter i { color: #111827; }\n.s5-instagram i { color: #E1306C; }\n.s5-youtube i { color: #FF0000; }\n\n.s5-triple {\n  min-width: 760px;\n  max-width: min(1500px, calc(100vw - 64px));\n  padding: 12px 14px;\n  display: flex;\n  align-items: center;\n  gap: 10px;\n}\n\n.s5-rotate {\n  min-width: 700px;\n  max-width: min(1380px, calc(100vw - 64px));\n  display: flex;\n  align-items: stretch;\n  overflow: hidden;\n}\n\n.s5-rotate .s5-label-wrap {\n  min-width: 164px;\n  background: #0f172a;\n  color: #fff;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  letter-spacing: .1em;\n  font-size: 12px;\n  font-weight: 800;\n  text-transform: uppercase;\n}\n\n.s5-rotator {\n  flex: 1;\n  min-height: 66px;\n  position: relative;\n  padding: 0 14px;\n}\n\n.s5-item {\n  position: absolute;\n  inset: 0 14px;\n  display: flex;\n  align-items: center;\n  gap: 10px;\n  opacity: 0;\n  animation: s5Cycle var(--cycle, 9s) linear infinite;\n}\n\n.s5-item:nth-child(1) { animation-delay: 0s; }\n.s5-item:nth-child(2) { animation-delay: calc(var(--cycle, 9s) / 3); }\n.s5-item:nth-child(3) { animation-delay: calc((var(--cycle, 9s) / 3) * 2); }\n\n.s5-item i {\n  width: 1.2em;\n  text-align: center;\n  font-size: 20px;\n}\n\n.s5-item .platform {\n  min-width: 118px;\n  font-size: 12px;\n  font-weight: 700;\n  letter-spacing: .1em;\n  text-transform: uppercase;\n  color: #374151;\n}\n\n.s5-item .handle {\n  font-size: clamp(20px, 1.6vw, 34px);\n  font-weight: 700;\n  line-height: 1;\n  color: #111827;\n}\n\n.s5-banner {\n  width: min(1880px, calc(100vw - 10px));\n  margin: 0 auto 8px;\n  display: flex;\n  align-items: center;\n  gap: 10px;\n  border-radius: 12px;\n  padding: 9px 10px;\n}\n\n.s5-banner .s5-track {\n  flex: 1;\n  min-width: 0;\n  overflow: hidden;\n}\n\n.s5-banner .s5-move {\n  display: inline-flex;\n  align-items: center;\n  white-space: nowrap;\n  gap: 22px;\n  padding-left: 18px;\n  animation: s5Ticker var(--speed, 20s) linear infinite;\n}\n\n.s5-banner .s5-move span {\n  font-size: clamp(17px, 1.25vw, 28px);\n  font-weight: 700;\n  color: #0f172a;\n}\n\n.s5-stack {\n  min-width: 430px;\n  max-width: min(760px, calc(100vw - 64px));\n  padding: 12px;\n  display: flex;\n  flex-direction: column;\n  gap: 8px;\n}\n\n.s5-stack .row {\n  border-radius: 10px;\n  border: 1px solid rgba(15,23,42,.12);\n  background: #ffffff;\n  display: flex;\n  align-items: center;\n  gap: 10px;\n  padding: 10px 12px;\n  font-size: clamp(16px, 1.12vw, 22px);\n  font-weight: 700;\n}\n\n.s5-stack .row i {\n  width: 1.1em;\n  text-align: center;\n  font-size: 18px;\n}\n\n.s5-minimal {\n  min-width: 620px;\n  max-width: min(1100px, calc(100vw - 64px));\n  padding: 12px 14px;\n  display: flex;\n  align-items: center;\n  gap: 12px;\n}\n\n.s5-minimal .live-dot {\n  width: 9px;\n  height: 9px;\n  border-radius: 999px;\n  background: #2563eb;\n  animation: s5Pulse 1.5s ease-in-out infinite;\n}\n\n.s5-minimal .title {\n  font-size: 12px;\n  letter-spacing: .12em;\n  text-transform: uppercase;\n  font-weight: 800;\n  color: #1d4ed8;\n}\n\n.s5-minimal .text {\n  font-size: clamp(18px, 1.32vw, 28px);\n  font-weight: 700;\n  color: #111827;\n}\n\n@media (max-width: 1080px) {\n  .s5-pos-bl, .s5-pos-br, .s5-pos-bc { left: 14px; right: 14px; transform: none; }\n  .s5-pos-br { left: auto; }\n  .s5-triple, .s5-rotate, .s5-stack, .s5-minimal { min-width: 0; max-width: calc(100vw - 28px); }\n  .s5-banner { width: calc(100vw - 10px); }\n}\n"
