    "html": "<div class=\"c-lt c-pos-br\" data-state=\"{{state}}\" data-mode=\"{{animMode}}\" style=\"--bg:linear-gradient(135deg,#3b1f0f,#c2410c);--fg:#fff7ed;--sub:#fed7aa;--accent:#fb923c;--bd:rgba(251,146,60,.34);--glow:rgba(251,146,60,.2);\">\n  <div class=\"c-shell c-sermon c-row\">\n    <div class=\"c-bar c-e3\"></div>\n    <div class=\"c-sermon-copy\">\n      <span class=\"c-kicker c-e3\">{{label}}</span>\n      <p class=\"c-title c-e1\">{{title}}</p>\n      <p class=\"c-sub c-e2\">{{subtitle}}</p>\n      <p class=\"c-meta c-e3\">{{meta}}</p>\n    </div>\n  </div>\n</div>",
