    "html": "<div class=\"c-lt c-pos-bl\" data-state=\"{{state}}\" data-mode=\"{{animMode}}\" style=\"--bg:linear-gradient(135deg,#0f172a,#1f2937);--fg:#f8fafc;--sub:#cbd5e1;--accent:#2dd4bf;--bd:rgba(45,212,191,.32);--glow:rgba(45,212,191,.18);\">\n  <div class=\"c-shell c-sermon c-row\">\n    <div class=\"c-bar c-e3\"></div>\n    <div class=\"c-sermon-copy\">\n      <span class=\"c-kicker c-e3\">{{label}}</span>\n      <p class=\"c-title c-e1\">{{title}}</p>\n      <p class=\"c-sub c-e2\">{{subtitle}}</p>\n      <p class=\"c-meta c-e3\">{{meta}}</p>\n    </div>\n  </div>\n</div>",
