    "html": "<div class=\"c-lt c-pos-bc\" data-state=\"{{state}}\" data-mode=\"{{animMode}}\" style=\"--bg:linear-gradient(135deg,#1f1438,#4c1d95);--fg:#f6f3ff;--sub:#ddd6fe;--accent:#a78bfa;--bd:rgba(167,139,250,.32);--glow:rgba(167,139,250,.2);\">\n  <div class=\"c-shell c-prayer c-row\">\n    <div class=\"c-pray-box c-e3\">PRAY</div>\n    <div class=\"c-prayer-copy\">\n      <p class=\"c-title c-e1\">{{title}}</p>\n      <p class=\"c-sub c-e2\">{{subtitle}}</p>\n      <p class=\"c-meta c-e3\">{{meta}}</p>\n    </div>\n  </div>\n</div>",
