    "html": "<div class=\"c-lt c-pos-bc\" data-state=\"{{state}}\" data-mode=\"{{animMode}}\" style=\"--bg:linear-gradient(135deg,#082032,#155e75);--fg:#ecfeff;--sub:#bae6fd;--accent:#22d3ee;--bd:rgba(34,211,238,.34);--glow:rgba(34,211,238,.2);\">\n  <div class=\"c-shell c-prayer c-row\">\n    <div class=\"c-pray-box c-e3\">PRAY</div>\n    <div class=\"c-prayer-copy\">\n      <p class=\"c-title c-e1\">{{title}}</p>\n      <p class=\"c-sub c-e2\">{{subtitle}}</p>\n      <p class=\"c-meta c-e3\">{{meta}}</p>\n    </div>\n  </div>\n</div>",
