    "html": "<div class=\"g-lt g-pos-bl\" data-state=\"{{state}}\" data-mode=\"{{animMode}}\" style=\"--bg:#ffffff;--fg:#052e16;--sub:#14532d;--accent:#16a34a;--bd:rgba(22,163,74,.24);--glow:rgba(22,163,74,.16);\">\n  <div class=\"g-panel g-bar-xl g-row\" style=\"max-width:min(1200px,calc(100vw - 70px));border-radius:999px;\">\n    <div class=\"g-copy\">\n      <p class=\"g-kicker g-e3\">{{label}}</p>\n      <p class=\"g-title g-e1\">{{headline}}</p>\n      <p class=\"g-sub g-e2\">{{details}}</p>\n    </div>\n  </div>\n</div>",
