    "html": "<div class=\"g-lt g-pos-bc\" data-state=\"{{state}}\" data-mode=\"{{animMode}}\" style=\"--bg:#ffffff;--fg:#0f172a;--sub:#334155;--accent:#0284c7;--bd:rgba(2,132,199,.22);--glow:rgba(2,132,199,.15);\">\n  <div class=\"g-panel g-split\">\n    <div class=\"g-split-left\">\n      <p class=\"g-title-condensed g-e1\">{{leftHeading}}</p>\n      <p class=\"g-sub g-e2\">{{leftText}}</p>\n    </div>\n    <div class=\"g-split-right\">\n      <div class=\"g-col\" style=\"flex:1;\">\n        <p class=\"g-title g-e1\" style=\"margin-top:0;color:#0284c7;\">{{centerTitle}}</p>\n        <p class=\"g-sub g-e2\">{{centerText}}</p>\n      </div>\n      <div class=\"g-divider g-e3\"></div>\n      <div class=\"g-col\" style=\"flex:1;\">\n        <span class=\"g-pill g-e3\">{{rightTitle}}</span>\n        <p class=\"g-method g-e2\" style=\"margin-top:8px;\">{{rightText}}</p>\n      </div>\n    </div>\n  </div>\n</div>",
