    "html": "<div class=\"g-lt g-pos-bc\" data-state=\"{{state}}\" data-mode=\"{{animMode}}\" style=\"--bg:#ffffff;--fg:#0f172a;--sub:#334155;--accent:#1d4ed8;--bd:rgba(29,78,216,.22);--glow:rgba(29,78,216,.14);\">\n  <div class=\"g-panel g-grid-3\">\n    <div class=\"g-cell\">\n      <p class=\"g-cell-title g-e3\">{{header}}</p>\n      <p class=\"g-cell-line g-e1\">{{method1Title}}</p>\n      <p class=\"g-sub g-e2\">{{method1Line}}</p>\n    </div>\n    <div class=\"g-cell\">\n      <p class=\"g-cell-title g-e3\">{{method2Title}}</p>\n      <p class=\"g-cell-line g-e1\">{{method2Line}}</p>\n    </div>\n    <div class=\"g-cell\">\n      <p class=\"g-cell-title g-e3\">{{method3Title}}</p>\n      <p class=\"g-cell-line g-e1\">{{method3Line}}</p>\n    </div>\n  </div>\n</div>",
    "category": "general",
