    "html": "<div class=\"g-lt g-pos-bc\" data-state=\"{{state}}\" data-mode=\"{{animMode}}\" style=\"--bg:linear-gradient(135deg,#ffffff,#f8f7ff);--fg:#2e1065;--sub:#5b21b6;--accent:#7c3aed;--bd:rgba(124,58,237,.24);--glow:rgba(124,58,237,.16);\">\n  <div class=\"g-panel g-bar-xl g-row\" style=\"max-width:min(1250px,calc(100vw - 70px));\">\n    <div class=\"g-copy\">\n      <p class=\"g-title g-e1\">{{headline}}</p>\n      <p class=\"g-sub g-e2\">{{details}}</p>\n      <p class=\"g-meta g-e3\">{{scripture}}</p>\n    </div>\n  </div>\n</div>",
