    "html": "<div class=\"c-lt c-pos-bc\" data-state=\"{{state}}\" data-mode=\"{{animMode}}\" style=\"--bg:linear-gradient(135deg,#3f1123,#be123c);--fg:#fff1f2;--sub:#fecdd3;--accent:#fb7185;--bd:rgba(251,113,133,.34);--glow:rgba(251,113,133,.2);\">\n  <div class=\"c-shell c-follow\">\n    <span class=\"c-pill c-e3\">{{label}}</span>\n    <div class=\"c-follow-list\">\n      <span class=\"c-follow-item c-e1\"><i class=\"fab fa-facebook-f\" aria-hidden=\"true\"></i>{{facebook}}</span>\n      <span class=\"c-follow-item c-e2\"><i class=\"fab fa-x-twitter\" aria-hidden=\"true\"></i>{{xHandle}}</span>\n      <span class=\"c-follow-item c-e3\"><i class=\"fab fa-instagram\" aria-hidden=\"true\"></i>{{instagram}}</span>\n    </div>\n  </div>\n</div>",
